const totalLines = 17;

// Genera un path ondulado para una altura Y dada, con un "phase" de variación
const makePath = (y, phase) => {
  const a = 12 * Math.sin(phase);
  const b = 10 * Math.cos(phase + 1);
  const c = 14 * Math.sin(phase + 2);
  const d = 8  * Math.cos(phase + 3);
  const e = 11 * Math.sin(phase + 4);
  const f = 9  * Math.cos(phase + 5);
  return `M-200,${y} C-80,${y+a} 120,${y+b} 260,${y+c} C400,${y+d} 560,${y+e} 720,${y+f} C880,${y-a} 1040,${y-b} 1200,${y-c} C1360,${y-d} 1520,${y-e} 1640,${y-f}`;
};

const BackgroundWaves = () => {
  return (
    <svg
      viewBox="0 0 1440 900"
      preserveAspectRatio="none"
      className="absolute inset-0 w-full h-full pointer-events-none z-0"
    >
      {[...Array(totalLines)].map((_, i) => {
        const y = (900 / (totalLines - 1)) * i;
        const duration = (8 + i * 0.7).toFixed(1);
        const phase0 = i * 0.6;

        // 5 keyframes con fases distintas para movimiento orgánico
        const values = [0, 1, 2, 3, 4, 0].map(k =>
          makePath(y, phase0 + k * 1.1)
        ).join(";");

        return (
          <path
            key={i}
            d={makePath(y, phase0)}
            fill="none"
            stroke="#C8B49A"
            strokeWidth={i % 4 === 0 ? "1.4" : "0.9"}
            opacity={0.4 + (i % 3) * 0.12}
          >
            <animate
              attributeName="d"
              values={values}
              dur={`${duration}s`}
              repeatCount="indefinite"
              calcMode="spline"
              keyTimes="0;0.2;0.4;0.6;0.8;1"
              keySplines="0.45 0 0.55 1;0.45 0 0.55 1;0.45 0 0.55 1;0.45 0 0.55 1;0.45 0 0.55 1"
              begin={`${-(i * 0.5).toFixed(1)}s`}
            />
          </path>
        );
      })}
    </svg>
  );
};

export default BackgroundWaves;
